from flask import Flask, request, jsonify
from pymongo import MongoClient
from bson import json_util
import os
import json

app = Flask(__name__)

MONGO_URI = os.getenv("MONGO_URI", "mongodb://localhost:27017")
MONGO_DB = os.getenv("MONGO_DB", "test")
MONGO_COLLECTION = os.getenv("MONGO_COLLECTION", "documents")

client = MongoClient(MONGO_URI)
db = client[MONGO_DB]
collection = db[MONGO_COLLECTION]

@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"})

@app.route("/filter", methods=["POST"])
def filter_documents():
    payload = request.get_json(force=True, silent=False) or {}
    where_expression = payload.get("where")

    if not isinstance(where_expression, str) or not where_expression.strip():
        return jsonify({"error": "A non-empty 'where' JavaScript expression is required"}), 400

    limit = payload.get("limit", 100)
    try:
        limit = max(1, min(int(limit), 1000))
    except Exception:
        return jsonify({"error": "'limit' must be an integer"}), 400

    projection = payload.get("projection")
    if projection is not None and not isinstance(projection, dict):
        return jsonify({"error": "'projection' must be an object if provided"}), 400

    query = {"$where": where_expression}

    try:
        cursor = collection.find(query, projection).limit(limit)
        results = list(cursor)
        return app.response_class(
            response=json_util.dumps({
                "count": len(results),
                "results": results
            }),
            status=200,
            mimetype="application/json"
        )
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route("/filter/raw", methods=["POST"])
def filter_documents_raw():
    payload = request.get_json(force=True, silent=False) or {}
    where_expression = payload.get("expression")

    if not isinstance(where_expression, str) or not where_expression.strip():
        return jsonify({"error": "A non-empty 'expression' string is required"}), 400

    try:
        query = {"$where": where_expression}
        results = list(collection.find(query).limit(100))
        return app.response_class(
            response=json.dumps({
                "query": query,
                "results": json.loads(json_util.dumps(results))
            }),
            status=200,
            mimetype="application/json"
        )
    except Exception as e:
        return jsonify({"error": str(e)}), 500

